# Module: interfaces
# Abstract type definitions for the shape hierarchy
# from enums import Color, ShapeType

from enums import Color

# Interface for renderable objects
@abstract
class IRenderable:
    @abstract
    def render(self) -> str: ...

    @abstract
    def get_color(self) -> Color: ...

# Interface for measurable shapes
@abstract
class IMeasurable:
    @abstract
    def area(self) -> float: ...

    @abstract
    def perimeter(self) -> float: ...

# Interface for positioned objects
@abstract
class IPositioned:
    x: float
    y: float

    @abstract
    def distance_to_origin(self) -> float: ...

