# Module: shapes
# Concrete shape implementations using cross-module imports
from enums import Color, ShapeType
from interfaces import IRenderable, IMeasurable, IPositioned
from structs import Point, Size

@abstract
class Shape(IRenderable, IMeasurable, IPositioned):
    _color: Color
    _type: ShapeType

    def __init__(self, color: Color, type: ShapeType):
        self.x = 0.0
        self.y = 0.0
        self._color = color
        self._type = type

    def get_color(self) -> Color:
        return self._color

    def get_type(self) -> ShapeType:
        return self._type

    @virtual
    def describe(self) -> str:
        return f"Shape at ({self.x}, {self.y})"

class Circle(Shape):
    _radius: float

    def __init__(self, radius: float, color: Color):
        super().__init__(color, ShapeType.CIRCLE)
        self._radius = radius

    @override
    def area(self) -> float:
        return 3.14159 * self._radius * self._radius

    @override
    def perimeter(self) -> float:
        return 2.0 * 3.14159 * self._radius

    @override
    def render(self) -> str:
        return f"Circle(r={self._radius}, color={self.get_color().name})"

    @override
    def describe(self) -> str:
        return f"Circle with radius {self._radius}"

    def get_diameter(self) -> float:
        return self._radius * 2.0

class Rectangle(Shape):
    _width: float
    _height: float

    def __init__(self, width: float, height: float, color: Color):
        super().__init__(color, ShapeType.RECTANGLE)
        self._width = width
        self._height = height

    @override
    def area(self) -> float:
        return self._width * self._height

    @override
    def perimeter(self) -> float:
        return 2.0 * (self._width + self._height)

    @override
    def render(self) -> str:
        return f"Rectangle({self._width}x{self._height}, color={self.get_color().name})"

    @override
    def describe(self) -> str:
        return f"Rectangle {self._width}x{self._height}"

    def get_size(self) -> Size:
        return Size(self._width, self._height)

# Utility class that uses all imports
class ShapeFactory:
    @static
    const DEFAULT_RADIUS: float = 5.0

    @static
    def create_circle(radius: float) -> Circle:
        return Circle(radius, Color.BLUE)

    @static
    def create_square(side: float) -> Rectangle:
        return Rectangle(side, side, Color.GREEN)
